examples.code:
// Horizontal (default)
<Stepper
  steps={[{ label: 'Account' }, { label: 'Profile' }, { label: 'Review' }]}
  currentStep={1}
/>

// Vertical with descriptions
<Stepper
  orientation="vertical"
  steps={[
    { label: 'Account', description: 'Create your account' },
    { label: 'Profile', description: 'Fill in your details' },
  ]}
  currentStep={0}
/>

// All steps completed (currentStep past last step)
<Stepper
  steps={[{ label: 'Order placed' }, { label: 'Shipped' }, { label: 'Delivered' }]}
  currentStep={3}
/>

// Checkout flow with testID for automation
<Stepper
  steps={[
    { label: 'Cart' },
    { label: 'Shipping' },
    { label: 'Payment' },
    { label: 'Confirm' },
  ]}
  currentStep={checkoutStep}
  testID="checkout-stepper"
/>
